/**
 * PATCH /users/:id/email
 *
 * Updates a user's email address.
 *
 * Injected dependency: userRepository
 *   - findById(id)           → User | null
 *   - findByEmail(email)     → User | null
 *   - updateEmail(id, email) → User  (returns updated user)
 */

// ─── Minimal Express-compatible interfaces ────────────────────────────────────
// Defined locally so this module has no runtime dependency on the express package.

export interface AppRequest {
  params: Record<string, string>;
  body: Record<string, unknown>;
}

export interface AppResponse {
  status(code: number): AppResponse;
  json(body: unknown): AppResponse;
}

// ─── Domain types ─────────────────────────────────────────────────────────────

export interface User {
  id: string;
  email: string;
  [key: string]: unknown;
}

export interface UserRepository {
  findById(id: string): Promise<User | null>;
  findByEmail(email: string): Promise<User | null>;
  updateEmail(id: string, email: string): Promise<User>;
}

// ─── Constants ────────────────────────────────────────────────────────────────

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// ─── Handler factory ──────────────────────────────────────────────────────────

/**
 * Factory — binds the repository and returns the Express route handler.
 *
 * Usage:
 *   router.patch('/users/:id/email', makePatchUserEmail(userRepository));
 */
export function makePatchUserEmail(
  userRepository: UserRepository,
): (req: AppRequest, res: AppResponse) => Promise<void> {
  return async function patchUserEmail(req: AppRequest, res: AppResponse): Promise<void> {
    const { id } = req.params;
    const { email } = req.body;

    // AC3 — validate email format before any DB work
    if (typeof email !== 'string' || !EMAIL_REGEX.test(email)) {
      res.status(400).json({
        error: {
          code: 'INVALID_EMAIL_FORMAT',
          message: 'The provided email address is not valid.',
        },
      });
      return;
    }

    // AC4 — user must exist
    const user = await userRepository.findById(id);
    if (!user) {
      res.status(404).json({
        error: {
          code: 'USER_NOT_FOUND',
          message: `No user found with id '${id}'.`,
        },
      });
      return;
    }

    // AC5 — same email → idempotent 200, no write
    if (user.email === email) {
      res.status(200).json({ user });
      return;
    }

    // AC2 — email must not be taken by a different user
    const existing = await userRepository.findByEmail(email);
    if (existing) {
      res.status(409).json({
        error: {
          code: 'EMAIL_ALREADY_IN_USE',
          message: 'That email address is already associated with another account.',
        },
      });
      return;
    }

    // AC1 — happy path: update and return new state
    const updatedUser = await userRepository.updateEmail(id, email);
    res.status(200).json({ user: updatedUser });
  };
}

