/**
 * Tests for PATCH /users/:id/email handler
 *
 * Coverage:
 *   AC1 — valid update → 200 + updated user
 *   AC2 — email taken by another user → 409 EMAIL_ALREADY_IN_USE
 *   AC3 — invalid email format → 400 INVALID_EMAIL_FORMAT
 *   AC4 — unknown user ID → 404 USER_NOT_FOUND
 *   AC5 — same email as current → 200 idempotent (no write)
 */

import { makePatchUserEmail, User, UserRepository, AppRequest, AppResponse } from './patchUserEmail';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeRes(): AppResponse & { _status: number | null; _body: unknown } {
  const res = {
    _status: null as number | null,
    _body: null as unknown,
    status(code: number) {
      this._status = code;
      return this;
    },
    json(body: unknown) {
      this._body = body;
      return this;
    },
  };
  return res;
}

function makeReq(
  { id = '42', email = 'new@example.com' }: { id?: string; email?: unknown } = {},
): AppRequest {
  return { params: { id }, body: { email } } as AppRequest;
}

// Base user fixtures
const ALICE: User = { id: '42', name: 'Alice', email: 'alice@example.com' };
const BOB: User   = { id: '99', name: 'Bob',   email: 'bob@example.com' };

// ---------------------------------------------------------------------------
// Repository factory — lets each test control exactly what the repo returns
// ---------------------------------------------------------------------------

function makeRepo(
  {
    user = ALICE as User | null,
    byEmail = null as User | null,
    updated = null as User | null,
  } = {},
): jest.Mocked<UserRepository> {
  return {
    findById:    jest.fn().mockResolvedValue(user),
    findByEmail: jest.fn().mockResolvedValue(byEmail),
    updateEmail: jest.fn().mockResolvedValue(updated ?? { ...user, email: 'new@example.com' }),
  };
}

// ---------------------------------------------------------------------------
// AC1 — valid update returns 200 with updated user
// ---------------------------------------------------------------------------

describe('AC1 — valid email update', () => {
  it('returns 200 with the updated user object', async () => {
    const updatedAlice: User = { ...ALICE, email: 'alice-new@example.com' };
    const repo = makeRepo({ user: ALICE, byEmail: null, updated: updatedAlice });
    const handler = makePatchUserEmail(repo);

    const req = makeReq({ id: '42', email: 'alice-new@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(res._status).toBe(200);
    expect(res._body).toEqual({ user: updatedAlice });
    expect(repo.updateEmail).toHaveBeenCalledWith('42', 'alice-new@example.com');
  });

  it('calls findById with the route param id', async () => {
    const repo = makeRepo({ user: ALICE });
    const handler = makePatchUserEmail(repo);

    await handler(makeReq({ id: '42', email: 'x@y.com' }), makeRes());

    expect(repo.findById).toHaveBeenCalledWith('42');
  });
});

// ---------------------------------------------------------------------------
// AC2 — email already in use by a DIFFERENT user → 409
// ---------------------------------------------------------------------------

describe('AC2 — email already in use', () => {
  it('returns 409 with EMAIL_ALREADY_IN_USE when another user owns the email', async () => {
    const repo = makeRepo({ user: ALICE, byEmail: BOB }); // BOB already has target email
    const handler = makePatchUserEmail(repo);

    const req = makeReq({ id: '42', email: 'bob@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(res._status).toBe(409);
    expect((res._body as { error: { code: string } }).error.code).toBe('EMAIL_ALREADY_IN_USE');
    expect(repo.updateEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC3 — invalid email format → 400
// ---------------------------------------------------------------------------

describe('AC3 — invalid email format', () => {
  const invalidEmails = [
    'not-an-email',
    'missing@tld',
    '@nodomain.com',
    'spaces in@email.com',
    '',
    null,
    undefined,
  ] as const;

  it.each(invalidEmails)('returns 400 for email=%p', async (badEmail) => {
    const repo = makeRepo();
    const handler = makePatchUserEmail(repo);

    const req: AppRequest = { params: { id: '42' }, body: { email: badEmail } };
    const res = makeRes();

    await handler(req, res);

    expect(res._status).toBe(400);
    expect((res._body as { error: { code: string } }).error.code).toBe('INVALID_EMAIL_FORMAT');
    // Must not hit the DB at all
    expect(repo.findById).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC4 — user not found → 404
// ---------------------------------------------------------------------------

describe('AC4 — user not found', () => {
  it('returns 404 with USER_NOT_FOUND when the id does not match any user', async () => {
    const repo = makeRepo({ user: null }); // findById returns null
    const handler = makePatchUserEmail(repo);

    const req = makeReq({ id: 'nonexistent', email: 'someone@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(res._status).toBe(404);
    expect((res._body as { error: { code: string } }).error.code).toBe('USER_NOT_FOUND');
    expect(repo.updateEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC5 — same email as current → 200, no write (idempotent)
// ---------------------------------------------------------------------------

describe('AC5 — same email is idempotent', () => {
  it('returns 200 with the current user and does NOT call updateEmail', async () => {
